import{_ as l,u as r,o as d,c,a as v,b as i,d as t,e,w as s,r as p,S as o}from"./index-C_lTwF0q.js";const m="/assets/chiara_al_pianoforte_bn-BpZWvTlw.JPG",u="/assets/mani_pianoforte_2_bn-CQVveP87.JPG",b={class:"chi-sono"},g={id:"arti-marziali",class:"section martial"},_={class:"container"},z={class:"martial__grid"},h={class:"martial__content"},f={class:"martial__principles"},C={class:"martial__principle"},y={class:"martial__principle"},S={class:"martial__principle"},P={class:"martial__principle"},M={class:"section section--alt didattica"},q={class:"container"},B={style:{"text-align":"center","margin-top":"2.5rem"}},A={class:"section section--dark cta-section"},V={class:"container",style:{"text-align":"center"}},D={__name:"ChiSonoPage",setup(L){return r({title:"Chi Sono | Chiara Dalla Torre - Maestro di Pianoforte",meta:[{name:"description",content:"Scopri il percorso di Chiara Dalla Torre: dagli studi al Conservatorio Steffani alle Masterclass internazionali, dalle arti marziali alla didattica pianistica."},{name:"keywords",content:"Chiara Dalla Torre biografia, pianista San Donà di Piave, Conservatorio Steffani, arti marziali e musica, insegnante pianoforte"}]}),(x,a)=>{const n=p("router-link");return d(),c("div",b,[a[23]||(a[23]=v('<section class="page-hero" data-v-ae0176b3><div class="container" data-v-ae0176b3><h1 data-v-ae0176b3>Chi Sono</h1><div class="section__divider" style="margin-top:1rem;" data-v-ae0176b3></div><p class="page-hero__sub" data-v-ae0176b3> Dalla musica alla disciplina, il mio percorso verso l&#39;insegnamento </p></div></section><section class="section bio" data-v-ae0176b3><div class="container" data-v-ae0176b3><div class="bio__grid" data-v-ae0176b3><div class="bio__content" data-v-ae0176b3><h2 data-v-ae0176b3>Il Mio Percorso Musicale</h2><div class="section__divider" style="margin-left:0;" data-v-ae0176b3></div><p data-v-ae0176b3> Nata a <strong data-v-ae0176b3>San Donà di Piave nel 1993</strong>, ho iniziato lo studio del pianoforte all&#39;età di 9 anni. A 13 anni sono stata ammessa al <strong data-v-ae0176b3>Conservatorio di Musica &quot;A. Steffani&quot;</strong> di Castelfranco Veneto, dove ho studiato sotto la guida del M° Francesco Bencivenga. Nel 2010 ho proseguito i miei studi seguita dal M° Irene Russo, <strong data-v-ae0176b3>diplomandomi brillantemente nel 2016</strong>. </p><p data-v-ae0176b3> Durante gli anni di Conservatorio ho avuto l&#39;opportunità di seguire <strong data-v-ae0176b3>Masterclass con pianisti di fama internazionale</strong>: Pietro de Maria, Filippo Gamba, Andrea Lucchesini, Jesús M. Gómez Rodríguez, Brenno Ambrosini, Sébastien Risler e Annibale Rebaudengo. Ognuno di questi incontri ha arricchito il mio linguaggio musicale e la mia sensibilità interpretativa. </p><h3 style="margin-top:2rem;" data-v-ae0176b3>Attività Concertistica</h3><p data-v-ae0176b3> Tra il 2011 e il 2016 ho partecipato annualmente alla rassegna <em data-v-ae0176b3>Sabati in Villa</em> presso Villa Barbarella di Castelfranco Veneto, sia come solista che in formazioni cameristiche. </p><p data-v-ae0176b3> Nel 2012 ho preso parte al progetto <em data-v-ae0176b3>L&#39;integrale dei concerti per 2, 3 e 4 tastiere e orchestra di J.S. Bach</em>, eseguendo il Concerto per due tastiere e orchestra in Do minore BWV 1062 presso il Teatro Accademico di Castelfranco Veneto. </p><p data-v-ae0176b3> Per molti anni ho affiancato all&#39;attività solistica anche quella di <strong data-v-ae0176b3>duo pianistico</strong> con la pianista italo-giapponese Anna Sembokuya Samarani, esibendomi alla rassegna pianistica itinerante <em data-v-ae0176b3>InterPiano Duo</em>, organizzata in collaborazione con i conservatori &quot;Arrigo Pedrollo&quot; di Vicenza e &quot;Benedetto Marcello&quot; di Venezia. </p><p data-v-ae0176b3> Ho dedicato gran parte del mio percorso di studi alla <strong data-v-ae0176b3>musica da camera</strong>, affrontando repertori vasti con formazioni differenti, intensificando la preparazione principalmente nella formazione di duo e trio con flauto traverso. </p></div><div class="bio__sidebar" data-v-ae0176b3><img src="'+m+'" alt="Chiara Dalla Torre al pianoforte" class="bio__image-photo" loading="lazy" data-v-ae0176b3><div class="bio__highlights" data-v-ae0176b3><div class="bio__highlight" data-v-ae0176b3><span class="bio__highlight-number" data-v-ae0176b3>2016</span><span class="bio__highlight-label" data-v-ae0176b3>Diploma al Conservatorio</span></div><div class="bio__highlight" data-v-ae0176b3><span class="bio__highlight-number" data-v-ae0176b3>15+</span><span class="bio__highlight-label" data-v-ae0176b3>Anni di studio</span></div><div class="bio__highlight" data-v-ae0176b3><span class="bio__highlight-number" data-v-ae0176b3>3</span><span class="bio__highlight-label" data-v-ae0176b3>Paesi in concerto</span></div></div></div></div></div></section><section class="section section--alt international" data-v-ae0176b3><div class="container" data-v-ae0176b3><h2 class="section__title" data-v-ae0176b3>Esperienze Internazionali</h2><div class="section__divider" data-v-ae0176b3></div><p class="section__subtitle" data-v-ae0176b3> La musica non conosce confini: le mie esperienze oltre l&#39;Italia </p><div class="timeline" data-v-ae0176b3><div class="timeline__item" data-v-ae0176b3><div class="timeline__year" data-v-ae0176b3>2011</div><div class="timeline__content" data-v-ae0176b3><h3 data-v-ae0176b3>Royal Conservatory — Anversa, Belgio</h3><p data-v-ae0176b3>Selezionata per uno stage pianistico presso il prestigioso conservatorio belga.</p></div></div><div class="timeline__item" data-v-ae0176b3><div class="timeline__year" data-v-ae0176b3>2015</div><div class="timeline__content" data-v-ae0176b3><h3 data-v-ae0176b3>Lemmensinstituut — Lovanio, Belgio</h3><p data-v-ae0176b3>Esibizione presso l&#39;istituto musicale di Lovanio.</p></div></div><div class="timeline__item" data-v-ae0176b3><div class="timeline__year" data-v-ae0176b3>2016</div><div class="timeline__content" data-v-ae0176b3><h3 data-v-ae0176b3>Prima Produzione Discografica</h3><p data-v-ae0176b3> Registrazione di musiche di Bach/Busoni, pubblicata dal Conservatorio di Castelfranco Veneto. </p></div></div><div class="timeline__item" data-v-ae0176b3><div class="timeline__year" data-v-ae0176b3>2018</div><div class="timeline__content" data-v-ae0176b3><h3 data-v-ae0176b3>Auditorium Maene — Bruxelles, Belgio</h3><p data-v-ae0176b3>Concerto presso il rinomato Auditorium Maene nella capitale belga.</p></div></div></div></div></section>',3)),i("section",g,[i("div",_,[i("div",z,[i("div",h,[a[8]||(a[8]=i("h2",null,"Arti Marziali e Musica",-1)),a[9]||(a[9]=i("div",{class:"section__divider",style:{"margin-left":"0"}},null,-1)),a[10]||(a[10]=i("p",{class:"martial__intro"}," Un binomio inaspettato che ha trasformato profondamente il mio modo di vivere la musica e l'insegnamento. ",-1)),a[11]||(a[11]=i("p",null," La pratica delle arti marziali è entrata nella mia vita come una disciplina parallela al pianoforte, e nel tempo si è rivelata una fonte straordinaria di crescita personale e artistica. Ciò che inizialmente poteva sembrare un mondo lontano dalla musica si è rivelato sorprendentemente complementare. ",-1)),i("div",f,[i("div",C,[i("h4",null,[t(o,{name:"body",size:18,color:"var(--color-accent)"}),a[0]||(a[0]=e(" Consapevolezza del Corpo",-1))]),a[1]||(a[1]=i("p",null," Le arti marziali insegnano a percepire ogni parte del corpo con precisione. Al pianoforte, questa consapevolezza si traduce in un controllo più fine del gesto tecnico, dalla postura delle mani al peso delle braccia. ",-1))]),i("div",y,[i("h4",null,[t(o,{name:"target",size:18,color:"var(--color-accent)"}),a[2]||(a[2]=e(" Concentrazione e Presenza",-1))]),a[3]||(a[3]=i("p",null," La capacità di essere completamente presenti nel momento — fondamentale nel combattimento — è la stessa che permette di entrare nel cuore di un brano musicale durante l'esecuzione. ",-1))]),i("div",S,[i("h4",null,[t(o,{name:"mountain",size:18,color:"var(--color-accent)"}),a[4]||(a[4]=e(" Perseveranza nel Percorso",-1))]),a[5]||(a[5]=i("p",null," Nelle arti marziali, come nella musica, il progresso arriva attraverso la ripetizione paziente e la fiducia nel processo. Non esistono scorciatoie, ma ogni passo è un mattone verso la maestria. ",-1))]),i("div",P,[i("h4",null,[t(o,{name:"wave",size:18,color:"var(--color-accent)"}),a[6]||(a[6]=e(" Equilibrio tra Forza e Morbidezza",-1))]),a[7]||(a[7]=i("p",null," Un buon marzialista sa quando usare la forza e quando cedere. Lo stesso vale per il pianista: la potenza di un fortissimo e la delicatezza di un pianissimo nascono dalla stessa intelligenza corporea. ",-1))])]),a[12]||(a[12]=i("p",{class:"martial__conclusion"}," Queste qualità — disciplina, pazienza, consapevolezza — le porto ogni giorno nelle mie lezioni. Credo che un insegnante debba trasmettere non solo nozioni musicali, ma anche un approccio alla crescita che va oltre la tastiera. ",-1))]),a[13]||(a[13]=i("div",{class:"martial__visual"},[i("div",{class:"martial__quote-card"},[i("blockquote",null,' "La disciplina è il ponte tra obiettivi e risultati." '),i("cite",null,"— Jim Rohn")]),i("img",{src:u,alt:"Mani al pianoforte - disciplina e arte",class:"martial__image-photo",loading:"lazy"})],-1))])])]),i("section",M,[i("div",q,[a[15]||(a[15]=i("h2",{class:"section__title"},"Formazione Didattica",-1)),a[16]||(a[16]=i("div",{class:"section__divider"},null,-1)),a[17]||(a[17]=i("p",{class:"section__subtitle"}," Un percorso continuo di crescita professionale nell'arte dell'insegnamento ",-1)),a[18]||(a[18]=i("div",{class:"didattica__content"},[i("p",null,[e(" La mia attività didattica è frutto di un percorso mirato svolto negli anni di studio, attraverso "),i("strong",null,"tirocinio attivo di classe"),e(" presso il Conservatorio. ")]),i("p",null,[e(" Nel 2021 ho preso parte al "),i("strong",null,"Corso di formazione metodologica e didattica strumentale pianistica"),e(", un'esperienza fondamentale incentrata sul repertorio, la prassi e l'approccio risolutivo, con particolare focus sulle varie metodologie di insegnamento e i metodi utilizzati. ")]),i("p",null," Credo fermamente che l'insegnamento sia un atto creativo tanto quanto l'esecuzione: ogni allievo è diverso, e il ruolo dell'insegnante è trovare la chiave giusta per sbloccare il potenziale di ciascuno. ")],-1)),i("div",B,[t(n,{to:"/lezioni",class:"btn btn--primary"},{default:s(()=>[...a[14]||(a[14]=[e(" Scopri le mie Lezioni ",-1)])]),_:1})])])]),i("section",A,[i("div",V,[a[20]||(a[20]=i("h2",null,"Vuoi Conoscermi Meglio?",-1)),a[21]||(a[21]=i("div",{class:"section__divider",style:{background:"var(--color-accent)"}},null,-1)),a[22]||(a[22]=i("p",{style:{"max-width":"500px",margin:"0 auto",color:"rgba(240,236,228,0.85)","font-size":"1.05rem"}}," Scrivimi per scoprire come possiamo iniziare insieme un percorso musicale su misura per te. ",-1)),t(n,{to:"/contatti",class:"btn btn--light",style:{"margin-top":"1.5rem"}},{default:s(()=>[...a[19]||(a[19]=[e(" Contattami ",-1)])]),_:1})])])])}}},k=l(D,[["__scopeId","data-v-ae0176b3"]]);export{k as default};
